  static Future<PaymentResponse> processInAppPurchase(
    List<String> productIds,
  ) async {
    final bool available = await InAppPurchase.instance.isAvailable();
    if (!available) {
      return PaymentResponse(
        success: false,
        message: 'In-app purchase not available',
      );
    }

    final Stream<List<PurchaseDetails>> purchaseStream =
        InAppPurchase.instance.purchaseStream;

    final List<ProductDetails> products =
        await InAppPurchase.instance.queryProductDetails(productIds.toSet());

    if (products.isEmpty) {
      return PaymentResponse(
        success: false,
        message: 'No products found',
      );
    }

    final List<PurchaseParam> purchaseParams = products
        .map((ProductDetails product) => PurchaseParam(
              productDetails: product,
              googlePlayPurchaseParams: const GooglePlayPurchaseParams(
                developerPayload: 'developer_payload',
              ),
            ))
        .toList();

    await InAppPurchase.instance.purchase(purchaseParams);

    return PaymentResponse(
      success: true,
      message: 'Purchase initiated',
    );
