        return PaymentResponse(
          success: result.success,
          message: result.success ? 'Payment successful' : 'Payment failed',
          transactionId: result.transactionId,
        );
      } else if (paymentMethod == 'apple_pay') {
        final ApplePayPaymentResult result =
