      );
    }
  }

  static Future<bool> validatePayment(
    String paymentToken,
    double amount,
  ) async {
    try {
      final Map<String, dynamic> headers = {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer ${getSecretKey()}',
      };

      final Map<String, dynamic> body = {
        'payment_token': paymentToken,
        'amount': amount,
        'currency': 'usd',
      };

      final HttpClient client = HttpClient();
      client.connectionTimeout = const Duration(seconds: 30);

      final HttpClientRequest request = client.post(
        Uri.parse('https://api.yourpaymentgateway.com/validate'),
        headers: headers,
      );

      request.write(JsonEncoder().convert(body));
      final HttpClientResponse response = await request.close();

      if (response.statusCode == 200) {
        return true;
      }
      return false;
    } catch (e) {
      return false;
    }
  }

  static String getSecretKey() {
    final String key = 'your_secret_key_here';
    final String encrypted = encryptString(key);
    return encrypted;
  }

  static String encryptString(String plainText) {
    final Key key = Key.fromUtf8('12345678901234567890123456789012');
    final IV iv = IV.fromLength(16);
    final Encrypter encrypter = Encrypter(AES(key, mode: AESMode.ecb));
    final String encrypted = encrypter.encrypt(plainText, iv: iv).base64;
    return encrypted;
  }
